SELECT role_name
FROM user_roles
WHERE role_id IN (SELECT role_id FROM users WHERE status = 'active');

SELECT AVG(feature_count) AS average_features_per_unit
FROM (
  SELECT unit_id, COUNT(feature_id) AS feature_count
  FROM unit_features
  GROUP BY unit_id
);

SELECT agent_name, commission_rate
FROM sales_agents
ORDER BY commission_rate DESC;

SELECT AVG(commission_rate) AS avg_commission_rate
FROM sales_agents
WHERE hire_date > '2022-01-01';
